#include <iostream>
#include <string>
#include <sstream>
#include <limits>

// Assume the user's solve() function is linked here
void solve();

int main() {
    std::string input_str;
    // Read the entire input for the test case, which might contain newlines
    std::string line;
    while (std::getline(std::cin, line)) {
        input_str += line + "\n";
    }
    if (!input_str.empty()) {
        input_str.pop_back(); // Remove the last newline to match typical input stream behavior
    }

    std::stringstream ss_in(input_str);
    std::stringstream ss_out;

    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();

    std::cin.rdbuf(ss_in.rdbuf());
    std::cout.rdbuf(ss_out.rdbuf());

    solve();

    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    std::cout << ss_out.str(); // Output captured result

    return 0;
}
